(function(){
  var page=document.body?document.body.dataset.page:"";
  var data={
    "physical-dashboard":{note:"物理节点总览展示仓库、港口和放行参考 proof。",wallet:[["Node operator","0xPHY...36","ok"],["Role","Physical Node Provider","ok"],["Real system","disabled","bad"]],proof:[["Physical root","0xphyroot...05","ok"],["Warehouse node","0xwh...001","ok"],["Port node","0xport...001","warn"]],state:[["Open nodes","5","warn"],["Matched BL","1","ok"],["Official filing","none","bad"]],contract:[["Chain write","disabled","bad"],["Logistics link","ready","ok"],["Audit link","ready","ok"]]},
    "warehouse-goods-receipt":{note:"仓库页把入库、出库、数量和封条号绑定为支持证明。",wallet:[["Warehouse wallet","0xWH...77","ok"],["Role","Warehouse Node","ok"],["WMS connection","disabled","bad"]],proof:[["Receipt hash","0xwr...001","ok"],["Outbound hash","0xout...001","ok"],["Seal hash","0xseal...88a","warn"]],state:[["Quantity","2,000 units","ok"],["SKU match","yes","ok"],["Port match","pending","warn"]],contract:[["WMS write","none","bad"],["Quality decision","not warehouse","warn"],["Audit note","ready","ok"]]},
    "port-customs-clearance":{note:"港口页展示装柜、装船和放行参考，但不生成官方文件。",wallet:[["Port node wallet","0xPORT...19","ok"],["Broker role","reference only","warn"],["Official authority","none in P0","bad"]],proof:[["Container hash","0xctnr...7788","ok"],["Gate-in hash","0xgate...1420","ok"],["Release ref hash","0xclear...001","warn"]],state:[["Seal matched","yes","ok"],["Vessel loaded","yes","ok"],["Official clearance","no","bad"]],contract:[["Port API","disabled","bad"],["Filing action","none","bad"],["Logistics support","ready","ok"]]},
    "physical-result":{note:"物理节点结果成为下游可读的支持证明，不改变角色事实。",wallet:[["Physical node owner","0xPHY...36","ok"],["Logistics reader","enabled","ok"],["Buyer role","not changed","ok"]],proof:[["Physical result","0xphyres...p0","ok"],["Warehouse + port root","0xphymap...01","ok"],["Audit bundle","0xaudit...001","ok"]],state:[["Physical proof","ready","ok"],["Business fact changed","no","ok"],["Official filing","none","bad"]],contract:[["Chain write","disabled","bad"],["Payment trigger","none","bad"],["Audit readable","yes","ok"]]}
  };
  var cfg=data[page];
  if(!cfg||document.getElementById("p0-physical-crypto-rail")||document.getElementById("p0-crypto-rail"))return;
  function st(){if(document.getElementById("p0-physical-crypto-rail-style"))return;var s=document.createElement("style");s.id="p0-physical-crypto-rail-style";s.textContent=".physical-crypto{border:1px solid rgba(52,211,153,.28);background:linear-gradient(135deg,rgba(52,211,153,.10),rgba(245,158,11,.08));border-radius:14px;box-shadow:var(--shadow);overflow:hidden}.physical-crypto-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.physical-crypto-card{border:1px solid rgba(159,178,201,.15);background:rgba(7,17,31,.30);border-radius:12px;padding:12px}.physical-crypto-card h3{margin:0 0 10px;font-size:15px}@media(max-width:1200px){.physical-crypto-grid{grid-template-columns:1fr}}";document.head.appendChild(s)}
  function badge(k){return k==="ok"?"ok":k==="warn"?"warn":"bad"}
  function rows(a){return a.map(function(r){return'<li><span><span class="small muted">'+r[0]+'</span><br><span class="strong">'+r[1]+'</span></span><span class="badge '+badge(r[2])+'">'+r[2]+'</span></li>'}).join("")}
  function run(){st();var sec=document.createElement("section");sec.id="p0-physical-crypto-rail";sec.className="section physical-crypto";sec.innerHTML='<div class="section-head"><div><h2>物理节点加密证明轨迹</h2><p class="section-sub">'+cfg.note+'</p></div><span class="badge ok">physical proof</span></div><div class="content physical-crypto-grid"><div class="physical-crypto-card"><h3>钱包 / 节点</h3><ul class="list">'+rows(cfg.wallet)+'</ul></div><div class="physical-crypto-card"><h3>物理证明</h3><ul class="list">'+rows(cfg.proof)+'</ul></div><div class="physical-crypto-card"><h3>节点状态</h3><ul class="list">'+rows(cfg.state)+'</ul></div><div class="physical-crypto-card"><h3>链上 / 审计状态</h3><ul class="list">'+rows(cfg.contract)+'</ul></div></div>';var rail=document.getElementById("p0-physical-rail");if(rail&&rail.parentNode){rail.parentNode.insertBefore(sec,rail.nextSibling);return}var hero=document.querySelector(".main .hero");if(hero&&hero.parentNode)hero.parentNode.insertBefore(sec,hero.nextSibling);else document.querySelector(".main")?.prepend(sec)}
  if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",run);else run();
})();